using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int st[100005], top, x = 0;
char ch;
int main(void)
{

	while (true)
	{
		scanf("%c", &ch);
		if (ch == '@') break;
		if (isdigit(ch)) x = x * 10 + ch - '0';
		else if (ch == '.') st[++top] = x, x = 0;
		else
		{
			int a = st[top--], b = st[top--];
			if (ch == '+') st[++top] = a + b;
			else if (ch == '-') st[++top] = b - a;
			else if (ch == '*') st[++top] = a * b;
			else if (ch == '/') st[++top] = b / a;
		}
	}
	printf("%d\n", st[1]);
	return false;
}
